toolUseResult.content:
/**
 * EmailMessage entity with Gmail API payload structure
 *
 * Primary entity representing a Gmail message with processing metadata,
 * structured to match Gmail API payload for direct integration.
 */

export interface EmailMessage {
  id: string; // Gmail message ID
  threadId: string; // Gmail thread ID
  gmailLabels: string[]; // Original Gmail labels (labelIds from Gmail API)

  // Gmail API payload structure
  payload: {
    partId?: string;
    mimeType: string;
    filename?: string;
    headers: EmailHeader[];
    body?: MessagePartBody;
    parts?: MessagePart[]; // For multipart messages
  };

  // Extracted/parsed fields for easier access
  subject: string; // Extracted from headers
  from: EmailAddress; // Parsed from "From" header
  to: EmailAddress[]; // Parsed from "To" header
  cc?: EmailAddress[]; // Parsed from "Cc" header
  bcc?: EmailAddress[]; // Parsed from "Bcc" header
  replyTo?: EmailAddress[]; // Parsed from "Reply-To" header
  date: Date; // Parsed from "Date" header
  messageId?: string; // Parsed from "Message-ID" header
  inReplyTo?: string; // Parsed from "In-Reply-To" header
  references?: string[]; // Parsed from "References" header

  // Content (extracted from payload)
  bodyPlain?: string;
  bodyHtml?: string;
  attachments?: EmailAttachment[];

  // Gmail API metadata
  snippet?: string; // Gmail-generated snippet
  historyId?: string;
  sizeEstimate?: number;

  // Processing metadata
  processedAt?: Date;
  processingSessionId?: string;
  isProcessed: boolean;

  // Enhanced for parallel processing
  processingBatch?: string; // Batch identifier for parallel processing
  processingPriority: number; // Processing order within batch
}

export interface EmailHeader {
  name: string; // Header name (e.g., "From", "To", "Subject")
  value: string; // Raw header value
}

export interface EmailAddress {
  email: string; // The actual email address
  name?: string; // Display name (if provided)
  raw: string; // Original header value for debugging
}

export interface MessagePartBody {
  attachmentId?: string;
  size?: number;
  data?: string; // Base64url encoded content
}

export interface MessagePart {
  partId: string;
  mimeType: string;
  filename?: string;
  headers: EmailHeader[];
  body?: MessagePartBody;
  parts?: MessagePart[]; // Nested parts for complex structures
}

export interface EmailAttachment {
  attachmentId: string;
  filename: string;
  mimeType: string;
  size: number;
  isInline: boolean;
  contentId?: string; // For inline attachments
}

/**
 * Email processing state transitions:
 * Unprocessed → Processing → Processed
 *     ↓           ↓           ↓
 *  Fetched → Classifying → Classified
 */
export type EmailProcessingState =
  | 'unprocessed'
  | 'fetched'
  | 'processing'
  | 'classifying'
  | 'processed'
  | 'classified';

/**
 * ClassificationSession entity with performance metrics
 *
 * Represents a batch classification session with enhanced audit capabilities
 * and parallel processing performance tracking.
 */

export interface ClassificationSession {
  id: string; // UUID
  startedAt: Date;
  completedAt?: Date;
  emailCount: number;
  successCount: number;
  errorCount: number;

  // Enhanced for new architecture
  processingMode: 'parallel' | 'sequential';
  batchSize: number;
  performanceMetrics: {
    totalDurationMs: number;
    avgEmailDurationMs: number;
    parallelStagesCount: number;
    databaseBatchOps: number;
  };

  // Configuration snapshot
  configVersion: string; // Hash of configuration used
  configSnapshot: object; // Full config for reproducibility

  // Error tracking
  errors: ClassificationError[];
  warnings: ClassificationWarning[];
}

export interface ClassificationError {
  emailId: string;
  stage: string;
  error: string;
  timestamp: Date;
  recoverable: boolean;
  retryCount: number;
}

export interface ClassificationWarning {
  emailId: string;
  stage: string;
  warning: string;
  timestamp: Date;
  impact: 'low' | 'medium' | 'high';
}

/**
 * Session processing modes:
 * - parallel: Multiple emails processed concurrently with parallel attribute detection
 * - sequential: One email at a time for debugging or low-resource environments
 */
export type ProcessingMode = 'parallel' | 'sequential';

/**
 * Performance tracking for parallel processing optimization
 */
export interface SessionPerformanceMetrics {
  totalDurationMs: number;
  avgEmailDurationMs: number;
  parallelStagesCount: number;
  databaseBatchOps: number;
  memoryUsageMB: number;
  peakConcurrency: number;
  stageExecutionTimes: Record<string, number>;
  parallelEfficiency: number; // Ratio of actual vs theoretical parallel speedup
}

/**
 * EmailClassification entity with explainability
 *
 * Core classification result with preserved sophistication and enhanced
 * explainability for the 9-stage classification pipeline.
 */

import { ExplainabilityTrace } from './explainability-trace';
import { ScoreBreakdown } from './score-breakdown';
import { AttributeContext } from './attribute-context';

export interface EmailClassification {
  id: string; // UUID
  emailId: string; // Foreign key to EmailMessage
  sessionId: string; // Foreign key to ClassificationSession

  // Classification results
  primaryCategory: string;
  secondaryCategories: string[];
  confidence: number; // 0.0 - 1.0

  // Enhanced explainability
  explainabilityTrace: ExplainabilityTrace;
  scoreBreakdown: ScoreBreakdown;
  attributeContext: AttributeContext;

  // Processing metadata
  processedAt: Date;
  processingDurationMs: number;
  aiRoutingUsed: boolean;

  // Parallel processing context
  batchPosition: number;
  parallelStageResults: ParallelStageResult[];
}

export interface ParallelStageResult {
  stageId: string;
  stageName: string;
  executionTimeMs: number;
  parallelWithStages: string[];
  dependentOnStages: string[];
  memoryUsageMB?: number;
  cacheHitsCount: number;
  errorCount: number;
}

/**
 * Classification confidence levels with business semantics
 */
export enum ConfidenceLevel {
  HIGH = 'high',           // > 0.8 - Can proceed without review
  MEDIUM = 'medium',       // 0.5 - 0.8 - May need review for important actions
  LOW = 'low',            // 0.2 - 0.5 - Needs review or AI assistance
  UNCERTAIN = 'uncertain', // < 0.2 - Requires manual classification
}

/**
 * Category assignment types for multi-label support
 */
export enum CategoryAssignmentType {
  PRIMARY = 'primary',           // Main category assignment
  SECONDARY = 'secondary',       // Additional relevant category
  DISAMBIGUATION = 'disambiguation', // Category used for tie-breaking
  AI_SUGGESTED = 'ai_suggested',     // Category suggested by AI routing
}

/**
 * Enhanced classification result with detailed reasoning
 */
export interface DetailedClassificationResult extends EmailClassification {
  confidenceLevel: ConfidenceLevel;
  categoryAssignments: CategoryAssignment[];
  alternativeCategories: AlternativeCategory[];
  classificationReasons: string[];
  requiredActions: RequiredAction[];
}

export interface CategoryAssignment {
  category: string;
  subtype?: string;
  confidence: number;
  assignmentType: CategoryAssignmentType;
  reasoning: string;
  sourceStages: string[]; // Which pipeline stages contributed
}

export interface AlternativeCategory {
  category: string;
  score: number;
  eliminationReason: string;
  closenessScore: number; // How close this was to being selected
}

export interface RequiredAction {
  action: 'manual_review' | 'ai_classification' | 'user_feedback' | 'reprocess_with_config';
  priority: 'low' | 'medium' | 'high';
  reason: string;
  suggestedBy: string; // Which stage suggested this action
}

/**
 * ExplainabilityTrace entity with 9-stage results
 *
 * Detailed audit trail preserving all sophisticated classification reasoning
 * per the scoring logic structure defined in SCORING_LOGIC.md.
 */

export interface ExplainabilityTrace {
  sessionId: string;
  emailId: string;

  // Pipeline stage results (preserved from n8n sophistication)
  hardAssertions: HardAssertionResult[];
  strongIndicators: StrongIndicatorResult[];
  ruleScoring: RuleEvaluationResult[];
  attributeDetection: AttributeDetectionResult[];
  attributeInfluence: AttributeInfluenceResult[];
  disambiguation: DisambiguationResult[];
  multiLabelSelection: MultiLabelResult[];
  aiRouting?: AIRoutingResult;

  // Enhanced for debugging and parallel processing
  stageTimings: Record<string, number>; // Stage execution times in ms
  parallelExecutionMap: Record<string, string[]>; // Which stages ran in parallel
  configurationRefs: Record<string, string>; // Config sections used

  // Decision audit
  finalDecisionReason: string;
  alternativeCategories: Array<{
    category: string;
    score: number;
    eliminationReason: string;
  }>;
}

/**
 * Hard Assertions stage results
 * Implements HIGH_CONFIDENCE_FLOOR logic per SCORING_LOGIC.md
 */
export interface HardAssertionResult {
  category: string;
  triggered: boolean;
  assertionType: 'from_domain' | 'subject_prefix' | 'from_address';
  matchedValue: string;
  confidence: 'HIGH_CONFIDENCE' | 'MEDIUM_CONFIDENCE'; // From config
  sourceGroup?: string; // Domain source group if applicable
  reason: string;
}

/**
 * Strong Indicator Seeding stage results
 * Implements diminishing returns seeding per SCORING_LOGIC.md
 */
export interface StrongIndicatorResult {
  category: string;
  indicatorType: 'from_domain' | 'subject_contains' | 'body_contains';
  matchedValue: string;
  seedScore: number;
  diminishingReturnsApplied: boolean;
  existingSeedScore: number; // Score before this indicator
  finalSeedScore: number; // Score after diminishing returns
  reason: string;
}

/**
 * Rule-based Scoring stage results
 * Implements subtype scoring formula with K_high/K_medium/K_low parameters
 */
export interface RuleEvaluationResult {
  category: string;
  subtype: string;
  tier: 'high' | 'medium' | 'low';
  matchedRules: RuleMatch[];
  rawScore: number;
  cappedScore: number;
  tierWeight: number; // K_high, K_medium, or K_low from config
  reason: string;
}

export interface RuleMatch {
  field: string;
  operation: string;
  matchedValue: string;
  ruleWeight: number;
  partialMatch: boolean;
}

/**
 * Attribute Detection stage results
 * Implements detectors and derived attributes per SCORING_LOGIC.md
 */
export interface AttributeDetectionResult {
  attribute: string;
  detected: boolean;
  detectionMethod: 'direct' | 'derived';
  sourceField?: string; // For direct detection
  derivationLogic?: string; // For derived attributes
  confidence: number;
  parallelProcessed: boolean;
  dependencies: string[]; // Other attributes this detection depended on
  reason: string;
}

/**
 * Attribute Influence stage results
 * Implements attribute bonus mapping and role enforcement per SCORING_LOGIC.md
 */
export interface AttributeInfluenceResult {
  targetCategory: string;
  attributeUsed: string;
  roleType: 'CORE' | 'PRIMARY_BOOST' | 'SECONDARY_BOOST' | 'DISAMBIGUATOR' | 'FILTER';
  bonusAmount: number;
  scoreBefore: number;
  scoreAfter: number;
  capApplied: boolean;
  reason: string;
}

/**
 * Disambiguation stage results
 * Implements pairwise adjustments per SCORING_LOGIC.md
 */
export interface DisambiguationResult {
  involvedCategories: string[];
  adjustmentType: 'pairwise' | 'confidence_gap';
  scoreAdjustments: Record<string, number>;
  winningCategory: string;
  confidenceGap: number;
  reason: string;
}

/**
 * Multi-label Selection stage results
 * Implements selection logic per SCORING_LOGIC.md
 */
export interface MultiLabelResult {
  selectedCategories: string[];
  rejectedCategories: Array<{
    category: string;
    score: number;
    rejectionReason: string;
  }>;
  coPresenceRulesApplied: string[];
  maxLabelsLimit: number;
  minSecondaryConfidence: number;
  reason: string;
}

/**
 * AI Routing stage results
 * Implements routing decisions per SCORING_LOGIC.md
 */
export interface AIRoutingResult {
  routingDecision: 'skip_ai' | 'feature_extraction' | 'full_classification';
  highConfidenceThreshold: number;
  aiRequiredThreshold: number;
  skipConditions: string[];
  aiResponse?: {
    extractedFeatures?: object;
    suggestedCategories?: string[];
    confidence: number;
    reasoning: string;
  };
  reason: string;
}

/**
 * Complete explainability trace structure per SCORING_LOGIC.md
 * This preserves the sophisticated n8n classification logic while
 * adding parallel processing metadata for the new architecture.
 */
export interface CompleteExplainabilityTrace extends ExplainabilityTrace {
  // Additional metadata for enhanced debugging
  configurationSnapshot: {
    version: string;
    hash: string;
    sectionsUsed: string[];
  };
  performanceMetadata: {
    totalProcessingTimeMs: number;
    parallelStagesExecuted: number;
    sequentialStagesExecuted: number;
    memoryUsagePeakMB: number;
  };
  qualityMetrics: {
    explainabilityScore: number; // How well this classification can be explained
    consistencyScore: number; // How consistent with similar past classifications
    confidenceCalibration: number; // How well-calibrated the confidence score is
  };
}

/**
 * ScoreBreakdown entity with parallel computation tracking
 *
 * Detailed score calculation with parallel processing context,
 * implementing category score aggregation per SCORING_LOGIC.md.
 */

export interface ScoreBreakdown {
  emailId: string;

  // Category scores (preserved structure from SCORING_LOGIC.md)
  categoryScores: Record<string, CategoryScoreDetails>;

  // Stage contributions with parallel processing metadata
  stageContributions: Record<string, StageContribution>;

  // Disambiguation tracking
  disambiguationApplied: DisambiguationApplication[];

  // Parallel processing optimization data
  parallelComputationMetrics: ParallelComputationMetrics;
}

/**
 * Category score details implementing the Category Score section
 * from SCORING_LOGIC.md with enhanced parallel processing tracking
 */
export interface CategoryScoreDetails {
  baseScore: number;
  hardAssertionBonus: number;
  strongIndicatorScore: number;
  ruleScore: number;
  attributeInfluenceScore: number;
  finalScore: number;

  // Enhanced breakdown for parallel processing
  parallelComputedComponents: string[]; // Which parts computed in parallel
  computationDurationMs: number;
  cacheHits: string[]; // Which calculations used cached results

  // Score aggregation tracking
  scoreAggregationSteps: ScoreAggregationStep[];
  cappingApplied: boolean;
  cappingReason?: string;
}

/**
 * Individual score aggregation step for detailed audit trail
 */
export interface ScoreAggregationStep {
  stepNumber: number;
  operation: 'seed' | 'add_rule_score' | 'apply_attribute_bonus' | 'apply_cap' | 'disambiguation_adjustment';
  scoreBefore: number;
  scoreAfter: number;
  contribution: number;
  source: string; // Which stage/rule/attribute contributed this
  reason: string;
  timestamp: Date;
}

/**
 * Stage contribution with parallel processing dependencies
 */
export interface StageContribution {
  contribution: number;
  confidence: number;
  processingMode: 'parallel' | 'sequential';
  dependencies: string[]; // Other stages this depended on

  // Performance tracking
  executionTimeMs: number;
  memoryUsageMB?: number;
  cacheUtilization: CacheUtilization;

  // Quality metrics
  contributionReliability: number; // How reliable this stage's contribution is
  contributionConsistency: number; // How consistent with past similar emails
}

export interface CacheUtilization {
  cacheHits: number;
  cacheMisses: number;
  cacheHitRate: number;
  cachedResults: string[]; // What was retrieved from cache
}

/**
 * Disambiguation application tracking
 */
export interface DisambiguationApplication {
  categories: string[];
  rule: string;
  scoreAdjustment: number;
  reason: string;

  // Parallel processing context
  appliedDuringParallelExecution: boolean;
  dependentOnParallelResults: string[];
  adjustmentTimestamp: Date;
}

/**
 * Parallel computation metrics for performance optimization
 */
export interface ParallelComputationMetrics {
  totalParallelOperations: number;
  parallelEfficiencyScore: number; // How well parallel processing was utilized
  bottleneckStages: string[]; // Stages that limited parallel performance

  // Resource utilization
  peakMemoryUsageMB: number;
  averageCpuUtilization: number;
  concurrentOperationsPeak: number;

  // Optimization opportunities
  parallelizableButSequential: string[]; // Operations that could be parallelized
  parallelConflicts: ParallelConflict[]; // Where parallel processing caused issues
}

export interface ParallelConflict {
  conflictType: 'resource_contention' | 'data_dependency' | 'cache_invalidation';
  involvedStages: string[];
  performanceImpact: number; // Milliseconds lost due to conflict
  resolution: string;
  mitigationSuggestion?: string;
}

/**
 * Enhanced score breakdown for debugging and optimization
 */
export interface DetailedScoreBreakdown extends ScoreBreakdown {
  // Additional analysis for score debugging
  scoreDistribution: {
    [category: string]: {
      percentileRank: number; // Where this score ranks among similar emails
      historicalAverage: number;
      standardDeviation: number;
      confidenceInterval: [number, number];
    };
  };

  // Cross-category analysis
  categoryCorrelations: {
    [categoryPair: string]: number; // Correlation between category scores
  };

  // Configuration impact analysis
  configurationSensitivity: {
    [parameter: string]: {
      currentValue: any;
